import React, { useMemo, useState } from 'react';
import {
  AlertCircle,
  ArrowRight,
  CheckCircle,
  Download,
  Edit2,
  Eye,
  FileText,
  LayoutDashboard,
  LogOut,
  Moon,
  Plus,
  Search,
  Sun,
  Upload,
  User2
} from 'lucide-react';

const hrCredentials = {
  role: 'HR',
  username: 'HR123',
  password: 'HR123'
};

const initialEmployees = [
  { id: 'EMP001', name: 'Rajesh Kumar', store: 'Store Alpha', role: 'Store Manager', avatar: 'https://ui-avatars.com/api/?background=0d6efd&color=fff&name=Rajesh+K' },
  { id: 'EMP002', name: 'Priya Singh', store: 'Store Beta', role: 'HR Associate', avatar: 'https://ui-avatars.com/api/?background=6610f2&color=fff&name=Priya+S' },
  { id: 'EMP003', name: 'Amit Patel', store: 'Store Gamma', role: 'Supervisor', avatar: 'https://ui-avatars.com/api/?background=20c997&color=fff&name=Amit+P' },
  { id: 'EMP004', name: 'Sneha Reddy', store: 'Store Delta', role: 'Cashier', avatar: 'https://ui-avatars.com/api/?background=0dcaf0&color=0069d9&name=Sneha+R' },
  { id: 'EMP005', name: 'Vikram Sharma', store: 'Store Epsilon', role: 'Assistant', avatar: 'https://ui-avatars.com/api/?background=6f42c1&color=fff&name=Vikram+S' }
];

const initialTemplates = [
      {
        id: 'T001',
        name: 'Warning Letter',
    description: 'Performance/discipline notice',
    content:
      'Date: {{Date}}\n\nTo,\n{{EmployeeName}}\n{{Store}}\n\nSubject: Warning Letter\n\nDear {{EmployeeName}},\n\nThis letter serves as a formal warning regarding [reason]. We expect immediate improvement in your conduct/performance.\n\nFurther violation may result in disciplinary action.\n\nRegards,\nHR Department',
        variables: ['Date', 'EmployeeName', 'Store']
      },
      {
        id: 'T002',
        name: 'Offer Letter',
    description: 'Offer for new employee',
    content:
      'Date: {{Date}}\n\nDear {{EmployeeName}},\n\nWe are pleased to offer you the position of {{Position}} at {{Store}}.\n\nYour employment will commence on {{JoiningDate}}.\n\nSalary: {{Salary}}\nReporting To: {{ReportingManager}}\n\nPlease confirm your acceptance by signing below.\n\nSincerely,\nHR Department',
        variables: ['Date', 'EmployeeName', 'Position', 'Store', 'JoiningDate', 'Salary', 'ReportingManager']
      }
    ];

const initialDocuments = [
      {
        id: 'DOC001',
        employeeId: 'EMP001',
        employeeName: 'Rajesh Kumar',
    store: 'Store Alpha',
        documentType: 'Driving License',
        expiryDate: '2025-01-15',
        status: 'valid',
    fileName: 'rajesh_license.pdf'
      },
      {
        id: 'DOC002',
        employeeId: 'EMP002',
        employeeName: 'Priya Singh',
    store: 'Store Beta',
        documentType: 'Medical Certificate',
        expiryDate: '2025-01-01',
        status: 'expiring',
    fileName: 'priya_medical.pdf'
  },
  {
    id: 'DOC003',
    employeeId: 'EMP003',
    employeeName: 'Amit Patel',
    store: 'Store Gamma',
    documentType: 'Employment Contract',
    expiryDate: '2024-07-01',
    status: 'expired',
    fileName: 'amit_contract.pdf'
  }
];

const statusClass = {
  valid: 'status-pill status-valid',
  expiring: 'status-pill status-warning',
  expired: 'status-pill status-danger'
};

const Toast = ({ toast }) => {
  if (!toast) return null;
  const Icon = toast.type === 'error' ? AlertCircle : CheckCircle;
  return (
    <div className="toast">
      <Icon size={18} />
      <span>{toast.message}</span>
    </div>
  );
};

const Welcome = ({ onProceed }) => (
  <div className="hero">
    <div className="hero-card">
      <p className="eyebrow">Centralized Employee Document Management System</p>
      <h1>Welcome to Centralized Employee Document Management System</h1>
      <p className="subtext">Secure, fast, centralized HR document automation</p>
      <button className="primary" onClick={onProceed}>
        Proceed to Login
        <ArrowRight size={18} />
      </button>
    </div>
