const Login = ({ onLogin, toast, theme }) => {
  const [form, setForm] = useState({ role: 'HR', username: '', password: '' });

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!form.username || !form.password) {
      onLogin({ ok: false, reason: 'Please enter credentials' });
      return;
    }

    const isValid =
      form.role === hrCredentials.role &&
      form.username === hrCredentials.username &&
      form.password === hrCredentials.password;

    if (isValid) {
      onLogin({ ok: true, role: form.role });
      return;
    }

    onLogin({ ok: false, reason: 'Invalid Credentials! Only HR Login Allowed' });
  };

  return (
    <div className={`login-shell ${theme === 'dark' ? 'dark' : ''}`}>
      <div className="login-card">
        <div className="login-icon">
          <User2 />
          </div>
        <div className="login-headings">
