  );
};

const UploadForm = ({ employees, onUpload, categories, onAddCategory }) => {
  const [form, setForm] = useState({
    employeeId: '',
    employeeName: '',
    store: '',
    documentType: '',
    expiryDate: '',
    fileName: '',
    status: 'valid'
  });
  const [progress, setProgress] = useState(0);

  const handleEmployeeChange = (id) => {
    const emp = employees.find((e) => e.id === id);
    setForm({
      ...form,
      employeeId: id,
      employeeName: emp?.name || '',
      store: emp?.store || ''
    });
  };

  const handleUpload = () => {
    if (!form.employeeId || !form.documentType || !form.fileName) return;
    setProgress(15);
    setTimeout(() => setProgress(60), 400);
    setTimeout(() => {
      setProgress(100);
      onUpload(form);
      setForm({ employeeId: '', employeeName: '', store: '', documentType: '', expiryDate: '', fileName: '', status: 'valid' });
      setTimeout(() => setProgress(0), 800);
    }, 900);
  };

  return (
    <div className="panel">
      <div className="panel-head">
        <div>
          <p className="eyebrow">Document Upload</p>
          <h3>Upload Employee Documents</h3>
          <p className="subtext">Attach certificates, IDs, contracts and more.</p>
