              </div>

      <div className="grid two">
        <label>
          Employee
          <select value={form.employeeId} onChange={(e) => handleEmployeeChange(e.target.value)}>
                    <option value="">Select Employee</option>
            {employees.map((emp) => (
                      <option key={emp.id} value={emp.id}>
                        {emp.id} - {emp.name} ({emp.store})
