                    ))}
                  </select>
                  </label>

        <label>
          Document Type
          <select value={form.documentType} onChange={(e) => setForm({ ...form, documentType: e.target.value })}>
            <option value="">Select type</option>
            {categories.map((c) => (
              <option key={c}>{c}</option>
