const App = () => {
  const [route, setRoute] = useState('home');
  const [toast, setToast] = useState(null);
  const [theme, setTheme] = useState('light');
  const [activeMenu, setActiveMenu] = useState('upload');
  const [categories, setCategories] = useState(['ID Proof', 'Driving License', 'Medical Certificate', 'Training Certificate', 'Employment Contract']);
  const [documents, setDocuments] = useState(initialDocuments);

  const [templates] = useState(initialTemplates);
  const [employees] = useState(initialEmployees);

  const showToast = (message, type = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 2000);
  };

  const handleLogin = (result) => {
    if (result.ok) {
      showToast('Welcome HR!');
      setTimeout(() => setRoute('dashboard'), 900);
    } else {
      showToast(result.reason || 'Invalid Credentials! Only HR Login Allowed', 'error');
    }
  };

  const handleLogout = () => {
    showToast('Successfully Logged Out');
    setTimeout(() => {
      setRoute('login');
      setActiveMenu('upload');
    }, 700);
  };

  const handleUpload = (doc) => {
    const newDoc = {
      ...doc,
      id: `DOC${String(documents.length + 1).padStart(3, '0')}`,
      status: doc.expiryDate ? getStatus(doc.expiryDate) : 'valid'
    };
    setDocuments([newDoc, ...documents]);
    showToast('Upload successful');
  };

  const handleGenerate = (template, employeeId) => {
    const emp = employees.find((e) => e.id === employeeId);
    if (!emp) {
      showToast('Select an employee to auto-fill', 'error');
      return;
    }
    const filled = template.content
      .replace(/{{EmployeeName}}/g, emp.name)
      .replace(/{{Store}}/g, emp.store)
      .replace(/{{Position}}/g, emp.role || 'Role')
      .replace(/{{Date}}/g, new Date().toLocaleDateString())
      .replace(/{{JoiningDate}}/g, new Date().toLocaleDateString())
      .replace(/{{Salary}}/g, 'Confidential')
      .replace(/{{ReportingManager}}/g, 'Reporting Manager');
    const blob = new Blob([filled], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${template.name}_${emp.name}.txt`;
    a.click();
    showToast('Letter generated & downloaded');
  };

  const getStatus = (expiry) => {
    const exp = new Date(expiry);
    const now = new Date();
    const diff = (exp - now) / (1000 * 60 * 60 * 24);
    if (diff < 0) return 'expired';
    if (diff < 30) return 'expiring';
    return 'valid';
  };

  const toggleTheme = () => setTheme(theme === 'dark' ? 'light' : 'dark');

  return (
    <div className={`app ${theme === 'dark' ? 'dark' : ''}`}>
      {route === 'home' && <Welcome onProceed={() => setRoute('login')} />}
      {route === 'login' && <Login onLogin={handleLogin} toast={toast} theme={theme} />}
      {route === 'dashboard' && (
        <DashboardShell
          onLogout={handleLogout}
          active={activeMenu}
          setActive={setActiveMenu}
          documents={documents}
          employees={employees}
          templates={templates}
          onUpload={handleUpload}
          onAddCategory={() => {
            const input = prompt('Enter new category name');
            if (input) setCategories([input, ...categories]);
          }}
          categories={categories}
          onGenerate={handleGenerate}
          theme={theme}
          toggleTheme={toggleTheme}
        />
      )}
      {toast && route !== 'login' && <Toast toast={toast} />}
    </div>
  );
};

export default App;
